import { useEffect, useState, type ReactNode } from 'react';
import { createRoot, type Root } from 'react-dom/client';
import { cls, useNamespace } from '../../utils';
import { CloseIcon, StatusIcon, type StatusType } from '../Message/StatusIcon';

export type NotificationType = StatusType;

export type NotificationPosition =
  | 'top-right'
  | 'top-left'
  | 'bottom-right'
  | 'bottom-left';

export interface NotificationOptions {
  /** Bold heading. */
  title?: ReactNode;
  /** Body content. */
  message?: ReactNode;
  /** Visual variant; drives the leading icon. Omit for no icon. */
  type?: NotificationType;
  /** Auto-dismiss delay in ms. `0` keeps the card until closed. Default `4500`. */
  duration?: number;
  /** Corner to stack the card in. Default `'top-right'`. */
  position?: NotificationPosition;
  /** Show a close button. Default `true`. */
  showClose?: boolean;
  /** Extra class on the card element. */
  className?: string;
  /** Fired after the card has closed. */
  onClose?: () => void;
}

/** Imperative handle returned by every `notification()` call. */
export interface NotificationHandle {
  close: () => void;
}

interface NotificationItem extends NotificationOptions {
  id: number;
}

let seed = 0;
let root: Root | null = null;
let container: HTMLElement | null = null;
let items: NotificationItem[] = [];

const DEFAULT_POSITION: NotificationPosition = 'top-right';

function isBrowser(): boolean {
  return typeof document !== 'undefined';
}

function ensureRoot(): Root | null {
  if (!isBrowser()) return null;
  if (!root) {
    container = document.createElement('div');
    container.className = 'ec-notification-container';
    document.body.appendChild(container);
    root = createRoot(container);
  }
  return root;
}

function flush(): void {
  root?.render(<NotificationList items={items} onRemove={remove} />);
}

function remove(id: number): void {
  const item = items.find((entry) => entry.id === id);
  items = items.filter((entry) => entry.id !== id);
  flush();
  item?.onClose?.();
}

interface NotificationCardProps {
  item: NotificationItem;
  onRemove: (id: number) => void;
}

function NotificationCard({ item, onRemove }: NotificationCardProps) {
  const ns = useNamespace('notification');
  const {
    title,
    message,
    type,
    duration = 4500,
    position = DEFAULT_POSITION,
    showClose = true,
  } = item;
  const [visible, setVisible] = useState(false);
  const isLeft = position.endsWith('left');

  useEffect(() => {
    const raf = requestAnimationFrame(() => setVisible(true));
    return () => cancelAnimationFrame(raf);
  }, []);

  useEffect(() => {
    if (duration <= 0) return;
    const timer = window.setTimeout(() => onRemove(item.id), duration);
    return () => window.clearTimeout(timer);
  }, [duration, item.id, onRemove]);

  const classes = cls(
    ns.b(),
    type && ns.m(type),
    ns.is('left', isLeft),
    ns.is('with-icon', Boolean(type)),
    visible && ns.is('visible'),
    item.className,
  );

  return (
    <div className={classes} role="alert" aria-live="polite">
      {type && (
        <span className={ns.e('icon')}>
          <StatusIcon type={type} />
        </span>
      )}
      <div className={ns.e('group')}>
        {title != null && <div className={ns.e('title')}>{title}</div>}
        {message != null && <div className={ns.e('content')}>{message}</div>}
      </div>
      {showClose && (
        <button
          type="button"
          className={ns.e('closebtn')}
          aria-label="Close"
          onClick={() => onRemove(item.id)}
        >
          <CloseIcon />
        </button>
      )}
    </div>
  );
}

function NotificationList({
  items: list,
  onRemove,
}: {
  items: NotificationItem[];
  onRemove: (id: number) => void;
}) {
  const ns = useNamespace('notification');
  const positions: NotificationPosition[] = [
    'top-right',
    'top-left',
    'bottom-right',
    'bottom-left',
  ];
  return (
    <>
      {positions.map((position) => {
        const group = list.filter(
          (item) => (item.position ?? DEFAULT_POSITION) === position,
        );
        if (group.length === 0) return null;
        return (
          <div key={position} className={cls(ns.e('wrapper'), ns.em('wrapper', position))}>
            {group.map((item) => (
              <NotificationCard key={item.id} item={item} onRemove={onRemove} />
            ))}
          </div>
        );
      })}
    </>
  );
}

function normalize(options: NotificationOptions | string): NotificationOptions {
  return typeof options === 'string' ? { message: options } : options;
}

function open(options: NotificationOptions | string): NotificationHandle {
  const opts = normalize(options);
  const id = ++seed;

  if (!ensureRoot()) {
    return { close: () => {} };
  }

  items = [...items, { ...opts, id }];
  flush();

  return { close: () => remove(id) };
}

type NotificationFn = (options: NotificationOptions | string) => NotificationHandle;

interface NotificationApi extends NotificationFn {
  success: NotificationFn;
  warning: NotificationFn;
  info: NotificationFn;
  error: NotificationFn;
  /** Close every open notification. */
  closeAll: () => void;
}

function withType(type: NotificationType): NotificationFn {
  return (options) => open({ ...normalize(options), type });
}

const notification = open as NotificationApi;
notification.success = withType('success');
notification.warning = withType('warning');
notification.info = withType('info');
notification.error = withType('error');
notification.closeAll = () => {
  for (const item of [...items]) remove(item.id);
};

export { notification };
/** Alias for the callable `notification` API. */
export const Notification = notification;

export * from './Notification';
export type {
  NotificationType,
  NotificationPosition,
  NotificationOptions,
  NotificationHandle,
} from './Notification';

.ec-notification__wrapper {
  display: flex;
  flex-direction: column;
  gap: 16px;
  position: fixed;
  z-index: var(--ec-index-popper);
  width: 330px;
  max-width: calc(100vw - 32px);
  pointer-events: none;
}

.ec-notification__wrapper--top-right {
  top: 16px;
  right: 16px;
  align-items: flex-end;
}

.ec-notification__wrapper--top-left {
  top: 16px;
  left: 16px;
  align-items: flex-start;
}

.ec-notification__wrapper--bottom-right {
  bottom: 16px;
  right: 16px;
  flex-direction: column-reverse;
  align-items: flex-end;
}

.ec-notification__wrapper--bottom-left {
  bottom: 16px;
  left: 16px;
  flex-direction: column-reverse;
  align-items: flex-start;
}

.ec-notification {
  --ec-notification-icon-color: var(--ec-color-info);

  display: flex;
  align-items: flex-start;
  box-sizing: border-box;
  gap: 12px;
  width: 100%;
  padding: 14px 16px;
  font-family: inherit;
  pointer-events: auto;
  background-color: var(--ec-bg-color-overlay);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color-lighter);
  border-radius: var(--ec-border-radius-base);
  box-shadow: var(--ec-box-shadow-light);
  opacity: 0;
  transform: translateX(100%);
  transition:
    opacity 0.3s,
    transform 0.3s;
}

.ec-notification.is-left {
  transform: translateX(-100%);
}

.ec-notification.is-visible {
  opacity: 1;
  transform: translateX(0);
}

.ec-notification__icon {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
  margin-top: 1px;
  font-size: 20px;
  color: var(--ec-notification-icon-color);
}

.ec-notification__group {
  flex: 1;
  min-width: 0;
}

.ec-notification__title {
  font-size: var(--ec-font-size-medium);
  font-weight: 700;
  line-height: 1.4;
  color: var(--ec-text-color-primary);
  overflow-wrap: anywhere;
}

.ec-notification__content {
  margin-top: 6px;
  font-size: var(--ec-font-size-base);
  line-height: 1.5;
  color: var(--ec-text-color-regular);
  overflow-wrap: anywhere;
}

.ec-notification__group:first-child .ec-notification__content,
.ec-notification__title + .ec-notification__content {
  margin-top: 6px;
}

.ec-notification__closebtn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  box-sizing: border-box;
  width: 16px;
  height: 16px;
  padding: 0;
  margin: 0;
  font-size: 14px;
  color: var(--ec-text-color-secondary);
  cursor: pointer;
  background-color: transparent;
  border: none;
  border-radius: var(--ec-border-radius-base);
  outline: none;
  transition: color 0.2s;
}

.ec-notification__closebtn:hover {
  color: var(--ec-text-color-regular);
}

.ec-notification__closebtn:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

/* ---- Types ---- */
.ec-notification--success {
  --ec-notification-icon-color: var(--ec-color-success);
}

.ec-notification--warning {
  --ec-notification-icon-color: var(--ec-color-warning);
}

.ec-notification--info {
  --ec-notification-icon-color: var(--ec-color-info);
}

.ec-notification--error {
  --ec-notification-icon-color: var(--ec-color-danger);
}
